import crypto from 'node:crypto';

function checkAppleCredentials(decryptedKey: { username: string; password: string }, username: string, password: string): boolean {
  const expectedUsername = Buffer.from(decryptedKey.username);
  const actualUsername = Buffer.from(username);
  const expectedPassword = Buffer.from(decryptedKey.password);
  const actualPassword = Buffer.from(password);

  const usernameMatch =
    expectedUsername.length === actualUsername.length &&
    crypto.timingSafeEqual(expectedUsername, actualUsername);
  const passwordMatch =
    expectedPassword.length === actualPassword.length &&
    crypto.timingSafeEqual(expectedPassword, actualPassword);

  return usernameMatch && passwordMatch;
}
```

